/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to a PDF file. LoadWWPContext.Call(&Context)
Do 'LoadGridState'
&Title = "Lançamento Pedidos"
//Report Template Source Header if &Context.EmpCod = 0 loadWWPContext.Call(&Context) Endif
For Each ORder EmpCod, FilCod Where EmpCod = &Context.EmpCod Where FilCod = &Context.FilCod &AppName = FilFan
&AddressLine1 = &Today.ToFormattedString() + ' ' + &Time.Trim() //FilLogNro.Trim() + ' - ' + FilBai.Trim() + ', '+ FilCidCodNomUfe.Trim()
&AddressLine2 = FilFonNum.Trim() if not FilEml.IsEmpty() if not &AddressLine2.IsEmpty() &AddressLine2 += ' / ' Endif &AddressLine2 += FilEml.Trim() Endif Exit EndFor
Print printTitle End
Do 'PrintFilters'
Do 'PrintColumnTitles'
Do 'PrintData'
Do 'PrintFooter'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'PrintFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not &PedBlq.IsEmpty() &FilterPedBlqValueDescription = &PedBlq.EnumerationDescription()
print printBlockFilterPedBlq EndIf If not &LctTip.IsEmpty() &FilterLctTipValueDescription = &LctTip.EnumerationDescription()
print printBlockFilterLctTip EndIf If not &LctAtuSal.IsEmpty() &FilterLctAtuSalValueDescription = &LctAtuSal.EnumerationDescription()
print printBlockFilterLctAtuSal EndIf If not &PedCod.IsEmpty() print printBlockFilterPedCod EndIf If not &PedSts.IsEmpty() &FilterPedStsValueDescription = &PedSts.EnumerationDescription()
print printBlockFilterPedSts EndIf If not &PedCliCod.IsEmpty() print printBlockFilterPedCliCod EndIf If not &PedCliRaz.IsEmpty() print printBlockFilterPedCliRaz EndIf If not &PedStsFin.IsEmpty() &FilterPedStsFinValueDescription = &PedStsFin.EnumerationDescription()
print printBlockFilterPedStsFin EndIf If not &FilCod.IsEmpty()
print printBlockFilterFilCod EndIf If not &PedFatFilCod.IsEmpty()
print printBlockFilterPedFatFilCod EndIf If not &PedDtaEms.IsEmpty() print printBlockFilterPedDtaEms EndIf If not &PedDtaEms_To.IsEmpty() &PedDtaEms_To_Description = format('%1 (%2)', "Emissão", "à") print printBlockFilterPedDtaEms_To EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'LCTCOD' &LctCod1.FromString(&GridStateDynamicFilter.Value) If not &LctCod1.IsEmpty() &LctCod = &LctCod1 print printBlockFilterLctCod EndIf Case &DynamicFiltersSelector1 = !'PEDDTAFAT' &PedDtaFat1.FromString(&GridStateDynamicFilter.Value) &PedDtaFat_To1.FromString(&GridStateDynamicFilter.ValueTo) If not &PedDtaFat1.IsEmpty() &FilterPedDtaFatDescription = "Faturado" &PedDtaFat = &PedDtaFat1 print printBlockFilterPedDtaFat EndIf If not &PedDtaFat_To1.IsEmpty() &FilterPedDtaFatDescription = format('%1 (%2)', "Faturado", "até") &PedDtaFat = &PedDtaFat_To1 print printBlockFilterPedDtaFat EndIf Case &DynamicFiltersSelector1 = !'PEDNUM' &PedNum1.FromString(&GridStateDynamicFilter.Value) If not &PedNum1.IsEmpty() &PedNum = &PedNum1 print printBlockFilterPedNum EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'LCTCOD' &LctCod2.FromString(&GridStateDynamicFilter.Value) If not &LctCod2.IsEmpty() &LctCod = &LctCod2 print printBlockFilterLctCod EndIf Case &DynamicFiltersSelector2 = !'PEDDTAFAT' &PedDtaFat2.FromString(&GridStateDynamicFilter.Value) &PedDtaFat_To2.FromString(&GridStateDynamicFilter.ValueTo) If not &PedDtaFat2.IsEmpty() &FilterPedDtaFatDescription = "Faturado" &PedDtaFat = &PedDtaFat2 print printBlockFilterPedDtaFat EndIf If not &PedDtaFat_To2.IsEmpty() &FilterPedDtaFatDescription = format('%1 (%2)', "Faturado", "até") &PedDtaFat = &PedDtaFat_To2 print printBlockFilterPedDtaFat EndIf Case &DynamicFiltersSelector2 = !'PEDNUM' &PedNum2.FromString(&GridStateDynamicFilter.Value) If not &PedNum2.IsEmpty() &PedNum = &PedNum2 print printBlockFilterPedNum EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'LCTCOD' &LctCod3.FromString(&GridStateDynamicFilter.Value) If not &LctCod3.IsEmpty() &LctCod = &LctCod3 print printBlockFilterLctCod EndIf Case &DynamicFiltersSelector3 = !'PEDDTAFAT' &PedDtaFat3.FromString(&GridStateDynamicFilter.Value) &PedDtaFat_To3.FromString(&GridStateDynamicFilter.ValueTo) If not &PedDtaFat3.IsEmpty() &FilterPedDtaFatDescription = "Faturado" &PedDtaFat = &PedDtaFat3 print printBlockFilterPedDtaFat EndIf If not &PedDtaFat_To3.IsEmpty() &FilterPedDtaFatDescription = format('%1 (%2)', "Faturado", "até") &PedDtaFat = &PedDtaFat_To3 print printBlockFilterPedDtaFat EndIf Case &DynamicFiltersSelector3 = !'PEDNUM' &PedNum3.FromString(&GridStateDynamicFilter.Value) If not &PedNum3.IsEmpty() &PedNum = &PedNum3 print printBlockFilterPedNum EndIf EndCase EndIf EndIf EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
print printBlockBeforeGrid print printBlockLines_titles
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod FilCod (PedCod) when &OrderedBy = 1 order EmpCod FilCod PedCod when &OrderedBy = 2 order EmpCod FilCod (PedDtaPrv) when &OrderedBy = 3 order EmpCod FilCod PedDtaPrv when &OrderedBy = 4 order EmpCod FilCod PedCliRaz when &OrderedBy = 5 order EmpCod FilCod PedDtaEms when &OrderedBy = 6 order EmpCod FilCod (PedDtaEms) when &OrderedBy = 7 order EmpCod FilCod PedDtaFat when &OrderedBy = 8 order EmpCod FilCod (PedDtaFat) when &OrderedBy = 9 order EmpCod FilCod PedDtaPrv when &OrderedBy = 10 order EmpCod FilCod (PedDtaPrv) when &OrderedBy = 11
using DSwwDevolucaoCompra(&PedBlq, &LctTip, &LctAtuSal, &PedCod, &PedSts, &PedCliCod , &PedCliRaz, &PedStsFin, &FilCod, &PedFatFilCod, &PedDtaEms, &PedDtaEms_To , &DynamicFiltersSelector1, &LctCod1, &PedDtaFat1, &PedDtaFat_To1, &PedNum1, &DynamicFiltersEnabled2 , &DynamicFiltersSelector2, &LctCod2, &PedDtaFat2, &PedDtaFat_To2, &PedNum2, &DynamicFiltersEnabled3 , &DynamicFiltersSelector3, &LctCod3, &PedDtaFat3, &PedDtaFat_To3, &PedNum3) &gridPedCliCodRaz = iif(PedCliCodRaz.Length() > 30, Substr(PedCliCodRaz,1,30)+'...', PedCliCodRaz) &PedStsDescription = PedSts.EnumerationDescription() &AuxFin = UPPER(Substr(PedStsFin.EnumerationDescription(), 1,3))
Do 'BeforePrintLine' print printBlockLines_data Do 'AfterPrintLine' EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"wwDevolucaoCompraGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"wwDevolucaoCompraGridState")) Else &GridState.FromXml(&Session.Get(!"wwDevolucaoCompraGridState")) Endif
&OrderedBy = &GridState.OrderedBy
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"PEDBLQ" &PedBlq.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"LCTTIP" &LctTip.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"LCTATUSAL" &LctAtuSal.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDCOD" &PedCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDSTS" &PedSts.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDCLICOD" &PedCliCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDCLIRAZ" &PedCliRaz.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDSTSFIN" &PedStsFin.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"FILCOD" &FilCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDFATFILCOD" &PedFatFilCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDDTAEMS" &PedDtaEms.FromString(&GridStateFilterValue.Value) &PedDtaEms_To.FromString(&GridStateFilterValue.ValueTo) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'BeforePrintLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
